 * Example usage to set ERC-1967 implementation slot:
 * ```solidity
 * contract ERC1967 {
 *     // Define the slot. Alternatively, use the SlotDerivation library to derive the slot.
 *     bytes32 internal constant _IMPLEMENTATION_SLOT = 0x360894a13ba1a3210667c828492db98dca3e2076cc3735a920a3ca505d382bbc;
 *
 *     function _getImplementation() internal view returns (address) {
 *         return StorageSlot.getAddressSlot(_IMPLEMENTATION_SLOT).value;
 *     }
 *
 *     function _setImplementation(address newImplementation) internal {
 *         require(newImplementation.code.length > 0);
 *         StorageSlot.getAddressSlot(_IMPLEMENTATION_SLOT).value = newImplementation;
 *     }
 * }
 * ```
 *
 * TIP: Consider using this library along with {SlotDerivation}.
 */
library StorageSlot {
    struct AddressSlot {
        address value;
    }

    struct BooleanSlot {
        bool value;
    }

    struct Bytes32Slot {
        bytes32 value;
    }

    struct Uint256Slot {
        uint256 value;
    }

    struct Int256Slot {
        int256 value;
    }

    struct StringSlot {
        string value;
    }

    struct BytesSlot {
        bytes value;
    }

    /**
     * @dev Returns an `AddressSlot` with member `value` located at `slot`.
     */
    function getAddressSlot(bytes32 slot) internal pure returns (AddressSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `BooleanSlot` with member `value` located at `slot`.
     */
    function getBooleanSlot(bytes32 slot) internal pure returns (BooleanSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `Bytes32Slot` with member `value` located at `slot`.
     */
    function getBytes32Slot(bytes32 slot) internal pure returns (Bytes32Slot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `Uint256Slot` with member `value` located at `slot`.
     */
    function getUint256Slot(bytes32 slot) internal pure returns (Uint256Slot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `Int256Slot` with member `value` located at `slot`.
     */
    function getInt256Slot(bytes32 slot) internal pure returns (Int256Slot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `StringSlot` with member `value` located at `slot`.
     */
    function getStringSlot(bytes32 slot) internal pure returns (StringSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns an `StringSlot` representation of the string storage pointer `store`.
     */
    function getStringSlot(string storage store) internal pure returns (StringSlot storage r) {
        assembly ("memory-safe") {
            r.slot := store.slot
        }
    }

    /**
     * @dev Returns a `BytesSlot` with member `value` located at `slot`.
     */
    function getBytesSlot(bytes32 slot) internal pure returns (BytesSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns an `BytesSlot` representation of the bytes storage pointer `store`.
     */
    function getBytesSlot(bytes storage store) internal pure returns (BytesSlot storage r) {
        assembly ("memory-safe") {
            r.slot := store.slot
        }
    }
}

contracts/AgentCovenant.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title AgentCovenant
 * @notice Individual covenant agreement between two AI agents
 * @dev Stores terms, handles disputes, manages escrow
 */
contract AgentCovenant {

    // ============ Enums ============

    enum CovenantStatus {
        PENDING,      // Waiting for counterparty acceptance
        ACTIVE,       // Covenant is active
        FULFILLED,    // Terms completed successfully
        DISPUTED,     // Under dispute
        RESOLVED,     // Dispute resolved
        EXPIRED,      // Past deadline
        BREACHED      // Terms violated
    }

    enum Party {
        INITIATOR,
        COUNTERPARTY
    }

    // ============ Structs ============

    struct CovenantTerms {
        bytes32 covenantType;      // TASK, ALLIANCE, ESCROW, etc.
        string termsIPFSHash;      // Detailed terms stored on IPFS
        uint256 createdAt;         // Creation timestamp
        uint256 expiresAt;         // Expiration timestamp
        uint256 stakeAmount;       // Amount staked by initiator
    }

    struct Milestone {
        string description;
        uint256 paymentAmount;
        bool completed;
        bool paid;
        uint256 completedAt;
    }

    // ============ State Variables ============

    address public immutable initiator;
    address public immutable counterparty;
    CovenantTerms public terms;
    CovenantStatus public status;

    Milestone[] public milestones;
    uint256 public totalMilestonePayments;
    uint256 public remainingBalance;

    address public feeRecipient;
    uint256 public protocolFeeBps;

    mapping(address => bool) public hasAccepted;
    mapping(address => bytes32) public agentCommitments; // Hashed commitments for milestones

    address public disputeResolver;
    string public disputeReason;
    uint256 public disputedAt;

    // ============ Events ============

    event CovenantAccepted(address indexed by);
    event CovenantActivated();
    event MilestoneAdded(uint256 indexed index, string description, uint256 payment);
    event MilestoneCompleted(uint256 indexed index, address indexed by);
    event MilestonePaid(uint256 indexed index, uint256 amount);
    event DisputeRaised(address indexed by, string reason);
    event DisputeResolved(address indexed resolver, uint256 initiatorAward, uint256 counterpartyAward);
    event CovenantFulfilled();
    event CovenantBreached(address indexed by, string reason);
    event FundsWithdrawn(address indexed by, uint256 amount);

    // ============ Modifiers ============

    modifier onlyParty() {
        require(
            msg.sender == initiator || msg.sender == counterparty,
            "Not a party"
        );
        _;
    }

    modifier onlyInitiator() {
        require(msg.sender == initiator, "Not initiator");
        _;
    }

    modifier onlyActive() {
        require(status == CovenantStatus.ACTIVE, "Not active");
        _;
    }

    // ============ Constructor ============

    constructor(
        address _initiator,
        address _counterparty,
        bytes32 _covenantType,
        string memory _termsIPFSHash,
        uint256 _duration,
        uint256 _stakeAmount,
        address _feeRecipient,
        uint256 _protocolFeeBps
    ) payable {
        initiator = _initiator;
        counterparty = _counterparty;
        feeRecipient = _feeRecipient;
        protocolFeeBps = _protocolFeeBps;
        remainingBalance = msg.value;

        terms = CovenantTerms({
            covenantType: _covenantType,
            termsIPFSHash: _termsIPFSHash,
            createdAt: block.timestamp,
            expiresAt: block.timestamp + _duration,
            stakeAmount: _stakeAmount
        });

        status = CovenantStatus.PENDING;
        hasAccepted[_initiator] = true; // Initiator auto-accepts
    }

    // ============ Core Functions ============

    /**
     * @notice Counterparty accepts the covenant
     */
    function acceptCovenant() external {
        require(msg.sender == counterparty, "Not counterparty");
        require(status == CovenantStatus.PENDING, "Not pending");
        require(block.timestamp < terms.expiresAt, "Expired");

        hasAccepted[counterparty] = true;
        status = CovenantStatus.ACTIVE;

        emit CovenantAccepted(counterparty);
        emit CovenantActivated();
    }

    /**
     * @notice Add a milestone with payment
     */
    function addMilestone(
        string calldata _description,
        uint256 _paymentAmount
    ) external onlyInitiator onlyActive {
        require(_paymentAmount <= remainingBalance, "Insufficient balance");

        milestones.push(Milestone({
            description: _description,
            paymentAmount: _paymentAmount,
            completed: false,
            paid: false,
            completedAt: 0
        }));

        totalMilestonePayments += _paymentAmount;

        emit MilestoneAdded(milestones.length - 1, _description, _paymentAmount);
    }

    /**
     * @notice Mark a milestone as completed
     */
    function completeMilestone(uint256 _milestoneIndex) external onlyActive {
        require(_milestoneIndex < milestones.length, "Invalid milestone");
        Milestone storage milestone = milestones[_milestoneIndex];
        require(!milestone.completed, "Already completed");

        milestone.completed = true;
        milestone.completedAt = block.timestamp;

        emit MilestoneCompleted(_milestoneIndex, msg.sender);
    }

    /**
     * @notice Pay out a completed milestone
     */
    function payMilestone(uint256 _milestoneIndex) external onlyInitiator onlyActive {
        require(_milestoneIndex < milestones.length, "Invalid milestone");
        Milestone storage milestone = milestones[_milestoneIndex];
        require(milestone.completed, "Not completed");
        require(!milestone.paid, "Already paid");

        milestone.paid = true;
        remainingBalance -= milestone.paymentAmount;

        // Calculate protocol fee
        uint256 fee = (milestone.paymentAmount * protocolFeeBps) / 10000;
        uint256 payment = milestone.paymentAmount - fee;

        // Pay fee
        (bool feeSuccess, ) = feeRecipient.call{value: fee}("");
        require(feeSuccess, "Fee transfer failed");

        // Pay counterparty
        (bool paySuccess, ) = counterparty.call{value: payment}("");
        require(paySuccess, "Payment failed");

        emit MilestonePaid(_milestoneIndex, payment);

        // Check if all milestones paid
        if (_allMilestonesPaid()) {
            status = CovenantStatus.FULFILLED;
            emit CovenantFulfilled();
        }
    }

    /**
     * @notice Raise a dispute
     */
    function raiseDispute(string calldata _reason) external onlyParty {
        require(
            status == CovenantStatus.ACTIVE || status == CovenantStatus.PENDING,
            "Cannot dispute"
        );

        status = CovenantStatus.DISPUTED;
        disputeReason = _reason;
        disputedAt = block.timestamp;

        emit DisputeRaised(msg.sender, _reason);
    }

    /**
     * @notice Resolve a dispute (called by factory/disputeDAO)
     */
    function resolveDispute(
        uint256 _initiatorAward,
        uint256 _counterpartyAward
    ) external {
        require(status == CovenantStatus.DISPUTED, "Not disputed");
        require(
            _initiatorAward + _counterpartyAward <= remainingBalance,
            "Awards exceed balance"
        );

        status = CovenantStatus.RESOLVED;
        disputeResolver = msg.sender;

        // Distribute awards
        if (_initiatorAward > 0) {
            remainingBalance -= _initiatorAward;
            (bool success, ) = initiator.call{value: _initiatorAward}("");
            require(success, "Initiator award failed");
        }

        if (_counterpartyAward > 0) {
            remainingBalance -= _counterpartyAward;
            (bool success, ) = counterparty.call{value: _counterpartyAward}("");
            require(success, "Counterparty award failed");
        }

        // Return remaining to initiator
        if (remainingBalance > 0) {
            uint256 refund = remainingBalance;
            remainingBalance = 0;
            (bool success, ) = initiator.call{value: refund}("");
            require(success, "Refund failed");
        }

        emit DisputeResolved(msg.sender, _initiatorAward, _counterpartyAward);
    }

    /**
     * @notice Declare covenant breached
     */
    function declareBreach(string calldata _reason) external onlyParty {
        require(status == CovenantStatus.ACTIVE, "Not active");
        require(block.timestamp > terms.expiresAt, "Not expired yet");

        status = CovenantStatus.BREACHED;

        // Return remaining funds to initiator
        if (remainingBalance > 0) {
            uint256 refund = remainingBalance;
            remainingBalance = 0;
            (bool success, ) = initiator.call{value: refund}("");
            require(success, "Refund failed");
        }

        emit CovenantBreached(msg.sender, _reason);
    }

    /**
     * @notice Withdraw remaining funds (initiator only, after expiry)
     */
    function withdrawRemaining() external onlyInitiator {
        require(
            status == CovenantStatus.EXPIRED || 
            status == CovenantStatus.BREACHED ||
            status == CovenantStatus.FULFILLED ||
            block.timestamp > terms.expiresAt,
            "Cannot withdraw yet"
        );

        require(remainingBalance > 0, "No balance");

        uint256 amount = remainingBalance;
        remainingBalance = 0;

        (bool success, ) = initiator.call{value: amount}("");
        require(success, "Withdraw failed");

        emit FundsWithdrawn(initiator, amount);
    }

    // ============ View Functions ============

    function getMilestoneCount() external view returns (uint256) {
        return milestones.length;
    }

    function getMilestone(uint256 _index) external view returns (Milestone memory) {
        require(_index < milestones.length, "Invalid index");
        return milestones[_index];
    }

    function isActive() external view returns (bool) {
        return status == CovenantStatus.ACTIVE;
    }

    function timeRemaining() external view returns (uint256) {
        if (block.timestamp >= terms.expiresAt) return 0;
        return terms.expiresAt - block.timestamp;
    }

    // ============ Internal Functions ============

    function _allMilestonesPaid() internal view returns (bool) {
        for (uint256 i = 0; i < milestones.length; i++) {
            if (!milestones[i].paid) return false;
        }
        return true;
    }

    // Allow receiving ETH
    receive() external payable {
        remainingBalance += msg.value;
    }
}

contracts/core/DisputeDAO.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "../interfaces/ICovenant.sol";
import "../interfaces/IReputationStake.sol";

/**
 * @title DisputeDAO
 * @notice Decentralized arbitration court for AI agent conflicts
 * @dev Uses commit-reveal voting with reputation-weighted decisions
 */
contract DisputeDAO is ReentrancyGuard {

    enum DisputeStatus {
        PENDING,        // Awaiting juror selection
        EVIDENCE,       // Evidence submission phase
        COMMIT,         // Jurors commit votes
        REVEAL,         // Jurors reveal votes
        APPEAL,         // Appeal window open
        RESOLVED,       // Final decision reached
        EXECUTED        // Resolution executed
    }

    enum VoteOption {
        ABSTAIN,
        FOR_INITIATOR,
        FOR_COUNTERPARTY,
        SPLIT
    }

    struct Dispute {
        uint256 id;
        address covenant;
        address initiator;
        address counterparty;
        uint256 stakeAmount;
        string reason;
        string evidenceIPFS;
        DisputeStatus status;
        uint256 createdAt;
        uint256 evidenceEndTime;
        uint256 commitEndTime;
        uint256 revealEndTime;
        uint256 resolutionTime;
        uint256 initiatorAward;
        uint256 counterpartyAward;
        address[] jurors;
        mapping(address => bytes32) commitHashes;
        mapping(address => VoteOption) revealedVotes;
        mapping(address => uint256) jurorReputation;
        uint256 totalReputationVoted;
        bool appealed;
        uint256 appealCount;
    }

    struct JurorProfile {
        bool isActive;
        uint256 totalCases;
        uint256 correctVotes;
        uint256 reputation;
        uint256 stakedAmount;
        uint256 rewardsEarned;
        uint256 lastActivity;
    }

    // ============ State Variables ============

    IERC20 public stakingToken;
    IReputationStake public reputationStake;

    uint256 public nextDisputeId = 1;
    mapping(uint256 => Dispute) public disputes;
    mapping(address => JurorProfile) public jurors;
    mapping(address => uint256[]) public jurorCases;

    // Parameters
    uint256 public minJurorStake = 1000e18; // 1000 tokens
    uint256 public jurorCount = 7; // 7 jurors per case
    uint256 public evidencePeriod = 3 days;
    uint256 public commitPeriod = 2 days;
    uint256 public revealPeriod = 1 days;
    uint256 public appealPeriod = 1 days;
    uint256 public minReputationToServe = 100;

    // Fees
    uint256 public disputeFee = 0.05 ether;
    uint256 public jurorRewardRate = 100; // 1% of stake per juror

    // Penalties
    uint256 public missedVotePenalty = 50; // 5% reputation
    uint256 public wrongVotePenalty = 25;  // 2.5% reputation

    // ============ Events ============

    event DisputeCreated(
        uint256 indexed disputeId,
        address indexed covenant,
        address indexed initiator,
        uint256 stakeAmount
    );

    event JurorSelected(uint256 indexed disputeId, address indexed juror);
    event EvidenceSubmitted(uint256 indexed disputeId, address indexed by, string ipfsHash);
    event VoteCommitted(uint256 indexed disputeId, address indexed juror);
    event VoteRevealed(uint256 indexed disputeId, address indexed juror, VoteOption vote);
    event DisputeResolved(
        uint256 indexed disputeId,
        uint256 initiatorAward,
        uint256 counterpartyAward,
        uint256 totalVotingPower
    );
    event JurorRewarded(uint256 indexed disputeId, address indexed juror, uint256 amount);
    event JurorPenalized(uint256 indexed disputeId, address indexed juror, uint256 amount, string reason);
    event AppealFiled(uint256 indexed disputeId, uint256 appealCount);

    // ============ Modifiers ============

    modifier onlyJuror(uint256 _disputeId) {
        require(_isJuror(_disputeId, msg.sender), "Not a juror");
        _;
    }

    modifier onlyDisputeParty(uint256 _disputeId) {
        Dispute storage d = disputes[_disputeId];
        require(
            msg.sender == d.initiator || msg.sender == d.counterparty,
            "Not a party"
        );
        _;
    }

    // ============ Constructor ============

    constructor(address _stakingToken, address _reputationStake) {
        stakingToken = IERC20(_stakingToken);
        reputationStake = IReputationStake(_reputationStake);
    }

    // ============ Juror Management ============

    function registerAsJuror(uint256 _stakeAmount) external nonReentrant {
        require(_stakeAmount >= minJurorStake, "Insufficient stake");
        require(!jurors[msg.sender].isActive, "Already registered");
        require(
            reputationStake.calculateReputation(msg.sender) >= minReputationToServe,
            "Insufficient reputation"
        );

        require(
            stakingToken.transferFrom(msg.sender, address(this), _stakeAmount),
            "Transfer failed"
        );

        jurors[msg.sender] = JurorProfile({
            isActive: true,
            totalCases: 0,
            correctVotes: 0,
            reputation: _stakeAmount / 1e18, // 1 token = 1 reputation point
            stakedAmount: _stakeAmount,
            rewardsEarned: 0,
            lastActivity: block.timestamp
        });
    }

    function unstakeAsJuror() external nonReentrant {
        JurorProfile storage juror = jurors[msg.sender];
        require(juror.isActive, "Not registered");
        require(juror.stakedAmount > 0, "No stake");

        // Check no active cases
        uint256[] storage cases = jurorCases[msg.sender];
        for (uint256 i = 0; i < cases.length; i++) {
            require(
                disputes[cases[i]].status == DisputeStatus.RESOLVED ||
                disputes[cases[i]].status == DisputeStatus.EXECUTED,
                "Active cases"
            );
        }

        uint256 amount = juror.stakedAmount;
        juror.isActive = false;
        juror.stakedAmount = 0;

        require(stakingToken.transfer(msg.sender, amount), "Transfer failed");
    }

    // ============ Dispute Creation ============

    function createDispute(
        address _covenant,
        string calldata _reason,
        string calldata _evidenceIPFS
    ) external payable nonReentrant returns (uint256 disputeId) {
        require(msg.value >= disputeFee, "Insufficient fee");

        ICovenant covenant = ICovenant(_covenant);
        require(uint256(covenant.status()) == 3, "Covenant not disputed"); // DISPUTED status

        disputeId = nextDisputeId++;
        Dispute storage d = disputes[disputeId];

        d.id = disputeId;
        d.covenant = _covenant;
        d.initiator = covenant.initiator();
        d.counterparty = covenant.counterparty();
        d.stakeAmount = covenant.remainingBalance();
        d.reason = _reason;
        d.evidenceIPFS = _evidenceIPFS;
        d.status = DisputeStatus.PENDING;
        d.createdAt = block.timestamp;
        d.evidenceEndTime = block.timestamp + evidencePeriod;

        // Select jurors
        _selectJurors(disputeId);

        emit DisputeCreated(disputeId, _covenant, d.initiator, d.stakeAmount);

        return disputeId;
    }

    function _selectJurors(uint256 _disputeId) internal {
        Dispute storage d = disputes[_disputeId];

        // In production, this would use Chainlink VRF for random selection
        // For now, use pseudo-random based on block hash
        for (uint256 i = 0; i < jurorCount; i++) {
            address juror = _getRandomJuror(_disputeId, i);
            if (juror != address(0)) {
                d.jurors.push(juror);
                jurorCases[juror].push(_disputeId);
                d.jurorReputation[juror] = jurors[juror].reputation;
                emit JurorSelected(_disputeId, juror);
            }
        }

        require(d.jurors.length >= 3, "Insufficient jurors");
        d.status = DisputeStatus.EVIDENCE;
    }

    function _getRandomJuror(uint256 _disputeId, uint256 _salt) internal view returns (address) {
        // Simplified - in production use Chainlink VRF
        bytes32 hash = keccak256(abi.encodePacked(
            blockhash(block.number - 1),
            _disputeId,
            _salt,
            block.timestamp
        ));

        // This would iterate through registered jurors
        // Simplified for demo
        return address(uint160(uint256(hash)));
    }

    // ============ Evidence Phase ============

    function submitEvidence(uint256 _disputeId, string calldata _evidenceIPFS) 
        external 
        onlyDisputeParty(_disputeId) 
    {
        Dispute storage d = disputes[_disputeId];
        require(d.status == DisputeStatus.EVIDENCE, "Not in evidence phase");
        require(block.timestamp <= d.evidenceEndTime, "Evidence period ended");

        emit EvidenceSubmitted(_disputeId, msg.sender, _evidenceIPFS);
    }

    function advanceToCommitPhase(uint256 _disputeId) external {
        Dispute storage d = disputes[_disputeId];
        require(d.status == DisputeStatus.EVIDENCE, "Not in evidence phase");
        require(block.timestamp > d.evidenceEndTime, "Evidence period active");

        d.status = DisputeStatus.COMMIT;
        d.commitEndTime = block.timestamp + commitPeriod;
    }

    // ============ Voting Phase ============

    function commitVote(uint256 _disputeId, bytes32 _commitHash) 
        external 
        onlyJuror(_disputeId) 
    {
        Dispute storage d = disputes[_disputeId];
        require(d.status == DisputeStatus.COMMIT, "Not in commit phase");
        require(block.timestamp <= d.commitEndTime, "Commit period ended");
        require(d.commitHashes[msg.sender] == bytes32(0), "Already committed");

        d.commitHashes[msg.sender] = _commitHash;
        emit VoteCommitted(_disputeId, msg.sender);
    }

    function revealVote(
        uint256 _disputeId,
        VoteOption _vote,
        uint256 _salt
    ) external onlyJuror(_disputeId) {
        Dispute storage d = disputes[_disputeId];
        require(d.status == DisputeStatus.COMMIT || d.status == DisputeStatus.REVEAL, "Not in reveal phase");

        if (d.status == DisputeStatus.COMMIT && block.timestamp > d.commitEndTime) {
            d.status = DisputeStatus.REVEAL;
            d.revealEndTime = block.timestamp + revealPeriod;
        }

        require(d.status == DisputeStatus.REVEAL, "Not in reveal phase");
        require(block.timestamp <= d.revealEndTime, "Reveal period ended");
        require(d.revealedVotes[msg.sender] == VoteOption.ABSTAIN, "Already revealed");

        // Verify commitment
        bytes32 commitHash = keccak256(abi.encodePacked(_vote, _salt));
        require(commitHash == d.commitHashes[msg.sender], "Invalid reveal");

        d.revealedVotes[msg.sender] = _vote;
        d.totalReputationVoted += d.jurorReputation[msg.sender];

        emit VoteRevealed(_disputeId, msg.sender, _vote);
    }

    // ============ Resolution ============

    function resolveDispute(uint256 _disputeId) external nonReentrant {
        Dispute storage d = disputes[_disputeId];
        require(d.status == DisputeStatus.REVEAL, "Not in reveal phase");
        require(block.timestamp > d.revealEndTime, "Reveal period active");

        // Calculate weighted votes
        uint256 initiatorWeight = 0;
        uint256 counterpartyWeight = 0;
        uint256 splitWeight = 0;

        for (uint256 i = 0; i < d.jurors.length; i++) {
            address juror = d.jurors[i];
            uint256 weight = d.jurorReputation[juror];

            if (d.revealedVotes[juror] == VoteOption.FOR_INITIATOR) {
                initiatorWeight += weight;
            } else if (d.revealedVotes[juror] == VoteOption.FOR_COUNTERPARTY) {
                counterpartyWeight += weight;
            } else if (d.revealedVotes[juror] == VoteOption.SPLIT) {
                splitWeight += weight;
            }
        }

        // Determine outcome
        if (initiatorWeight > counterpartyWeight && initiatorWeight > splitWeight) {
            // Initiator wins
            d.initiatorAward = d.stakeAmount;
            d.counterpartyAward = 0;
        } else if (counterpartyWeight > initiatorWeight && counterpartyWeight > splitWeight) {
            // Counterparty wins
            d.initiatorAward = 0;
            d.counterpartyAward = d.stakeAmount;
        } else {
            // Split decision
            d.initiatorAward = d.stakeAmount / 2;
            d.counterpartyAward = d.stakeAmount / 2;
        }

        d.status = DisputeStatus.RESOLVED;
        d.resolutionTime = block.timestamp;

        // Reward/penalize jurors
        _processJurorRewards(_disputeId, initiatorWeight > counterpartyWeight);

        emit DisputeResolved(
            _disputeId,
            d.initiatorAward,
            d.counterpartyAward,
            d.totalReputationVoted
        );
    }

    function _processJurorRewards(uint256 _disputeId, bool initiatorWon) internal {
        Dispute storage d = disputes[_disputeId];
        uint256 totalReward = (d.stakeAmount * jurorRewardRate) / 10000;
        uint256 rewardPerJuror = totalReward / d.jurors.length;

        for (uint256 i = 0; i < d.jurors.length; i++) {
            address juror = d.jurors[i];
            JurorProfile storage profile = jurors[juror];

            VoteOption vote = d.revealedVotes[juror];
            bool votedCorrectly = (initiatorWon && vote == VoteOption.FOR_INITIATOR) ||
                                 (!initiatorWon && vote == VoteOption.FOR_COUNTERPARTY);

            if (vote == VoteOption.ABSTAIN) {
                // Penalty for not voting
                profile.reputation = (profile.reputation * (10000 - missedVotePenalty)) / 10000;
                emit JurorPenalized(_disputeId, juror, missedVotePenalty, "Missed vote");
            } else if (!votedCorrectly) {
                // Penalty for wrong vote
                profile.reputation = (profile.reputation * (10000 - wrongVotePenalty)) / 10000;
                emit JurorPenalized(_disputeId, juror, wrongVotePenalty, "Wrong vote");
            } else {
                // Reward for correct vote
                profile.correctVotes++;
                profile.rewardsEarned += rewardPerJuror;
                require(stakingToken.transfer(juror, rewardPerJuror), "Reward failed");
                emit JurorRewarded(_disputeId, juror, rewardPerJuror);
            }

            profile.totalCases++;
            profile.lastActivity = block.timestamp;
        }
    }

    // ============ Appeal ============

    function fileAppeal(uint256 _disputeId, string calldata _reason) 
        external 
        payable 
        onlyDisputeParty(_disputeId) 
    {
        require(msg.value >= disputeFee * 2, "Insufficient appeal fee");
        Dispute storage d = disputes[_disputeId];
        require(d.status == DisputeStatus.RESOLVED, "Not resolved");
        require(!d.appealed, "Already appealed");
        require(d.appealCount < 2, "Max appeals reached");

        d.appealed = true;
        d.appealCount++;
        d.status = DisputeStatus.PENDING;

        // Reset and select new jurors
        delete d.jurors;
        _selectJurors(_disputeId);

        emit AppealFiled(_disputeId, d.appealCount);
    }

    // ============ Execution ============

    function executeResolution(uint256 _disputeId) external nonReentrant {
        Dispute storage d = disputes[_disputeId];
        require(d.status == DisputeStatus.RESOLVED, "Not resolved");
        require(
            block.timestamp > d.resolutionTime + appealPeriod || d.appealed,
            "Appeal period active"
        );

        ICovenant covenant = ICovenant(d.covenant);
        covenant.resolveDispute(d.initiatorAward, d.counterpartyAward);

        d.status = DisputeStatus.EXECUTED;
    }

    // ============ View Functions ============

    function _isJuror(uint256 _disputeId, address _addr) internal view returns (bool) {
        Dispute storage d = disputes[_disputeId];
        for (uint256 i = 0; i < d.jurors.length; i++) {
            if (d.jurors[i] == _addr) return true;
        }
        return false;
    }

    function getDispute(uint256 _disputeId) external view returns (
        address covenant,
        DisputeStatus status,
        uint256 stakeAmount,
        uint256 selectedJurorCount,
        bool canAppeal
    ) {
        Dispute storage d = disputes[_disputeId];
        return (
            d.covenant,
            d.status,
            d.stakeAmount,
            d.jurors.length,
            d.status == DisputeStatus.RESOLVED && !d.appealed && d.appealCount < 2
        );
    }

    function getJurors(uint256 _disputeId) external view returns (address[] memory) {
        return disputes[_disputeId].jurors;
    }

    function hasCommitted(uint256 _disputeId, address _juror) external view returns (bool) {
        return disputes[_disputeId].commitHashes[_juror] != bytes32(0);
    }

    function hasRevealed(uint256 _disputeId, address _juror) external view returns (bool) {
        return disputes[_disputeId].revealedVotes[_juror] != VoteOption.ABSTAIN;
    }
}

contracts/CovenantFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./AgentCovenant.sol";

/**
 * @title CovenantFactory
 * @notice Factory contract for deploying new covenant agreements between agents
 * @dev Part of the COVENANT Protocol for AI agent coordination
 */
contract CovenantFactory {

    // ============ State Variables ============

    /// @notice Array of all deployed covenants
    address[] public covenants;

    /// @notice Mapping from covenant address to creation timestamp
    mapping(address => uint256) public covenantCreationTime;

    /// @notice Mapping from agent pair to covenant address
    mapping(bytes32 => address) public agentPairToCovenant;

    /// @notice Protocol fee recipient (treasury)
    address public feeRecipient;

    /// @notice Protocol fee in basis points (100 = 1%)
    uint256 public protocolFeeBps = 100;

    /// @notice Minimum stake required to create covenants (in wei)
    uint256 public minimumStake = 0.01 ether;

    /// @notice Contract owner
    address public owner;

    // ============ Events ============

    event CovenantCreated(
        address indexed covenantAddress,
        address indexed initiator,
        address indexed counterparty,
        bytes32 covenantType,
        uint256 stakeAmount,
        uint256 timestamp
    );

    event FeeRecipientUpdated(address indexed oldRecipient, address indexed newRecipient);
    event ProtocolFeeUpdated(uint256 oldFee, uint256 newFee);
    event MinimumStakeUpdated(uint256 oldStake, uint256 newStake);

    // ============ Errors ============

    error InvalidAgentAddress();
    error CovenantAlreadyExists();
    error InsufficientStake();
    error Unauthorized();

    // ============ Modifiers ============

    modifier onlyOwner() {
        if (msg.sender != owner) revert Unauthorized();
        _;
    }

    // ============ Constructor ============

    constructor(address _feeRecipient) {
        if (_feeRecipient == address(0)) revert InvalidAgentAddress();
        owner = msg.sender;
        feeRecipient = _feeRecipient;
    }

    // ============ External Functions ============

    /**
     * @notice Create a new covenant between two agents
     * @param _counterparty The other agent in the covenant
     * @param _covenantType Type of covenant (TASK, ALLIANCE, ESCROW, etc.)
     * @param _termsIPFSHash IPFS hash of detailed terms
     * @param _duration Duration of the covenant in seconds
     * @return covenantAddress Address of the newly created covenant
     */
    function createCovenant(
        address _counterparty,
        bytes32 _covenantType,
        string calldata _termsIPFSHash,
        uint256 _duration
    ) external payable returns (address covenantAddress) {

        if (_counterparty == address(0) || _counterparty == msg.sender) {
            revert InvalidAgentAddress();
        }

        if (msg.value < minimumStake) {
            revert InsufficientStake();
        }

        // Check if covenant already exists between these agents
        bytes32 pairHash = keccak256(abi.encodePacked(
            msg.sender < _counterparty ? msg.sender : _counterparty,
            msg.sender < _counterparty ? _counterparty : msg.sender
        ));

        if (agentPairToCovenant[pairHash] != address(0)) {
            revert CovenantAlreadyExists();
        }

        // Calculate protocol fee
        uint256 protocolFee = (msg.value * protocolFeeBps) / 10000;
        uint256 stakeAmount = msg.value - protocolFee;

        // Transfer protocol fee
        (bool feeSuccess, ) = feeRecipient.call{value: protocolFee}("");
        require(feeSuccess, "Fee transfer failed");

        // Deploy new covenant
        AgentCovenant newCovenant = new AgentCovenant{
            value: stakeAmount
        }(
            msg.sender,
            _counterparty,
            _covenantType,
            _termsIPFSHash,
            _duration,
            stakeAmount,
            feeRecipient,
            protocolFeeBps
        );

        covenantAddress = address(newCovenant);
        covenants.push(covenantAddress);
        covenantCreationTime[covenantAddress] = block.timestamp;
        agentPairToCovenant[pairHash] = covenantAddress;

        emit CovenantCreated(
            covenantAddress,
            msg.sender,
            _counterparty,
            _covenantType,
            stakeAmount,
            block.timestamp
        );

        return covenantAddress;
    }

    /**
     * @notice Get total number of covenants created
     */
    function getCovenantCount() external view returns (uint256) {
        return covenants.length;
    }

    /**
     * @notice Get all covenants (with pagination)
     * @param _offset Starting index
     * @param _limit Maximum number to return
     */
    function getCovenants(uint256 _offset, uint256 _limit) 
        external 
        view 
        returns (address[] memory) 
    {
        uint256 end = _offset + _limit;
        if (end > covenants.length) {
            end = covenants.length;
        }

        address[] memory result = new address[](end - _offset);
        for (uint256 i = _offset; i < end; i++) {
            result[i - _offset] = covenants[i];
        }

        return result;
    }

    /**
     * @notice Check if a covenant exists between two agents
     */
    function covenantExists(address _agent1, address _agent2) 
        external 
        view 
        returns (bool) 
    {
        bytes32 pairHash = keccak256(abi.encodePacked(
            _agent1 < _agent2 ? _agent1 : _agent2,
            _agent1 < _agent2 ? _agent2 : _agent1
        ));
        return agentPairToCovenant[pairHash] != address(0);
    }

    // ============ Admin Functions ============

    function setFeeRecipient(address _newRecipient) external onlyOwner {
        emit FeeRecipientUpdated(feeRecipient, _newRecipient);
        feeRecipient = _newRecipient;
    }

    function setProtocolFee(uint256 _newFeeBps) external onlyOwner {
        require(_newFeeBps <= 1000, "Fee too high"); // Max 10%
        emit ProtocolFeeUpdated(protocolFeeBps, _newFeeBps);
        protocolFeeBps = _newFeeBps;
    }

    function setMinimumStake(uint256 _newMinimum) external onlyOwner {
        emit MinimumStakeUpdated(minimumStake, _newMinimum);
        minimumStake = _newMinimum;
    }

    function transferOwnership(address _newOwner) external onlyOwner {
        owner = _newOwner;
    }
}

